const output = $input.first().json.text || '';
const match = output.match(
  /PREP_PLAN_START([\s\S]*?)PREP_PLAN_END/
);
return [{
  json: {
    prepPlan: match ? match[1].trim() : output,
    jobTitle: $('Webhook').first().json.body.jobTitle,
    companyName: $('Webhook').first().json.body.companyName,
    interviewDate: $('Webhook').first().json.body.interviewDate
  }
}];
